app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, action } = req.body;

  if (action === 'deny') {
    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.append('error', 'access_denied');
    redirectUrl.searchParams.append('error_description', 'User denied authorization');
    if (state) {
      redirectUrl.searchParams.append('state', state);
    }
    return res.redirect(redirectUrl.toString());
  }

  if (!users[username] || users[username].password !== password) {
    return res.status(401).send('Invalid credentials');
  }

  const authCode = generateRandomString();
  
  authorizationCodes.set(authCode, {
    clientId: client_id,
    redirectUri: redirect_uri,
    scope: scope || '',
    username: username,
    expiresAt: Date.now() + 600000
  });

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  let authClientId = client_id;
  let authClientSecret = client_secret;

  if (!authClientId || !authClientSecret) {
    const authHeader = req.headers.authorization;
    if (authHeader && authHeader.startsWith('Basic ')) {
      const base64Credentials = authHeader.substring(6);
      const credentials = Buffer.from(base64Credentials, 'base64').toString('ascii');
      const [id, secret] = credentials.split(':');
      authClientId = id;
      authClientSecret = secret;
    }
  }

  if (!authClientId || !authClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  const client = clients[authClientId];
  if (!client || client.clientSecret !== authClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Only authorization_code grant type is supported' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'code is required' });
  }

  const authCodeData = authorizationCodes.get(code);
  if (!authCodeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  if (authCodeData.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (authCodeData.clientId !== authClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was issued to another client' });
  }

  if (authCodeData.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri mismatch' });
  }

  authorizationCodes.delete(code);

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();

  accessTokens.set(accessToken, {
    clientId: authClientId,
    username: authCodeData.username,
    scope: authCodeData.scope,
    expiresAt: Date.now() + 3600000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCodeData.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Bearer token required' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token expired' });
  }

  res.json({
    sub: tokenData.username,
    username: tokenData.username,
    scope: tokenData.scope
  });
});

setInterval(() => {
  const now = Date.now();
  
  for (const [code, data] of authorizationCodes.entries()) {
    if (data.expiresAt < now) {
      authorizationCodes.delete(code);
    }
  }
  
  for (const [token, data] of accessTokens.entries()) {
    if (data.expiresAt < now) {
      accessTokens.delete(token);
    }
  }
}, 60000);

